const proposicoes = $('Buscar últimas proposições').all().map(item => item.json);
const votacoes = $('Buscar últimas votações').all().map(item => item.json);

const textoProposicoes = proposicoes.map((p, index) => {
  return `${index + 1}. ${p.sigla_tipo} ${p.numero}/${p.ano} - ${p.data_apresentacao}
Ementa: ${p.ementa}
Resumo IA: ${p.resumo_ia || 'não disponível'}`;
}).join('\n\n');

const textoVotacoes = votacoes.map((v, index) => {
  return `${index + 1}. ${v.data} - ${v.sigla_orgao}
Descrição: ${v.descricao}
Aprovação: ${v.aprovacao}`;
}).join('\n\n');

const contexto = `
Você receberá dados públicos da Câmara dos Deputados.

Objetivo:
Gerar uma análise executiva breve para abrir um e-mail enviado a diretores de uma consultoria legislativa.

Últimas proposições:
${textoProposicoes}

Últimas votações:
${textoVotacoes}
`;

return [
  {
    json: {
      contexto,
      proposicoes,
      votacoes
    }
  }
];
